import React from 'react'
import Item from './Item'


export default function EditRoom(props) {
  let showItems=()=>{
    return props.room.items.map((i,n) => {
      return ( <Item name={props.i.name} item={i} n={n} turnOnOrOff={props.turnOnOrOff}/>)
  })}
  return (
    <div>
      {showItems}
      <Link to={"/"+props.name+"/addItems"}> <button >Edit room</button></Link> 
            <Link to={"/"}> <button>back</button></Link> 


    </div>
  )
}
